import axios from 'axios'

const url = 'api/'

class ServerTalker {
    static async loadQuestion(eventName, topicsNames, userID) {
        return new Promise ((resolve,reject) => {
            axios.post(url + "question/loadQuestion" , {
                eventName,
                topicsNames,
                userID
            })
            .then((res) => {
                if (res.data.status && res.data.question) {
                    const question = res.data.question;
                    resolve(question)
                } else {
                    reject(res.data)
                    console.log(res.data)
                }
            })
            .catch((err)=> {
                reject(err);
            })
            
        });
    }

    static async submitSolution(solution, questionID, userID) {
        return new Promise ((resolve,reject) => {
            axios.post(url + "question/submitSolution", {
                solution, 
                questionID,
                userID: userID
            })
                .then((res) => {
                    if (res.data.status) {
                        const reply = {
                            ...res.data,
                        }
                        resolve(reply)
                    } else {
                        reject("Error")
                    }
                })
                .catch((err)=> {
                    reject(err);
                })
            
        });
    }

    static async getEvents() {
        return new Promise ((resolve,reject) => {
            axios.get(url + "question/getEvents")
                .then((res) => {
                    const events = res.data.events;
                    resolve(events)
                })
                .catch((err)=> {
                    reject(err);
                })
            
        });
    }

}

