<template>
  <div>
    <div class="dropdown">
      <button class="btn dropdown-toggle" data-toggle="dropdown" aria-haspopup="true" aria-expanded="false" data-bs-toggle="dropdown">
        {{ question.event }}
      </button>
      <div class="dropdown-menu">
        <button class="btn dropdown-item" v-for="(event, index) in events" :key="index" @click="changeEvent(event)">{{event.name}}</button>
      </div>
    </div>
  </div>
</template>

<script>
import ServerTalker from '../ServerTalker'
export default {
    name: 'QuestionEditor',
    props: {
        userId: String,
    },
    async created() {
    try {
      this.events = await ServerTalker.getEvents()
    //   for (let event of this.events)
    //     for (let topic of event.topics)
    //       topic.checked = true
      this.question.event = this.events[0].name
    } catch(err) {
      this.error = err.message
    }
  },
  data() {
    return {
        events: null,

        question: {
            prompt: '',
            event: '',
            eventType: 'MultipleChoice',
        },
    }
  },
  methods: {
    changeEvent(event) {
      this.question.event = event.name
    },
  }
}
</script>
    
